                    <option value="price_desc" {{ request('sort') == 'price_desc' ? 'selected' : '' }}>Price: High to Low</option>
                </select>
            </div>
        </div>

        <div class="products-grid">
            @forelse($products as $product)
                <x-product-card :product="$product" />
            @empty
                <p>No products found.</p>
            @endforelse
        </div>

        {{ $products->withQueryString()->links('pagination.custom') }}
    </div>
</section>

<form id="filter-form" method="GET" action="{{ route('shop.catalog') }}" style="display: none;">
    @foreach(request()->except('sort') as $key => $value)
        @if(is_array($value))
            @foreach($value as $v)
                <input type="hidden" name="{{ $key }}[]" value="{{ $v }}">
            @endforeach
        @else
            <input type="hidden" name="{{ $key }}" value="{{ $value }}">
        @endif
    @endforeach
</form>
@endsection


@push('scripts')
<script>
    function toggleFilterGroup(header) {
        const group = header.closest('.filter-group');
        group.classList.toggle('collapsed');
    }

    document.addEventListener('DOMContentLoaded', function() {
        document.querySelectorAll('.filter-group.collapsed .accordion-icon').forEach(icon => {
            icon.style.transform = 'rotate(-90deg)';
        });
    });
</script>
@endpush